export type DubaiLocationFilter =
  | "Jumeirah"
  | "Al Barsha"
  | "Deira"
  | "Dubai Marina"
  | "Silicon Oasis"
  | "Mirdif"
  | "Sharjah"
  | "Ajman"
  | "Other Dubai";

export function getDubaiLocationFilter(area: string): DubaiLocationFilter {
  const a = area.toLowerCase();
  if (a.includes("jumeirah") || a.includes("jumeira") || a.includes("umm suqeim") || a.includes("al safa") || a.includes("al wasl")) return "Jumeirah";
  if (a.includes("al barsha") || a.includes("arjan") || a.includes("dubailand") || a.includes("motor city") || a.includes("sports city") || a.includes("mudon")) return "Al Barsha";
  if (a.includes("deira") || a.includes("al twar") || a.includes("al qusais") || a.includes("al nahda") || a.includes("al warqa") || a.includes("mirdif") || a.includes("al rashidiya") || a.includes("al mizhar") || a.includes("al khawaneej") || a.includes("festival city") || a.includes("al garhoud") || a.includes("muhaisnah")) return "Deira";
  if (a.includes("marina") || a.includes("jlt") || a.includes("jbr") || a.includes("emirates hills") || a.includes("springs") || a.includes("meadows") || a.includes("lakes") || a.includes("al furjan") || a.includes("discovery") || a.includes("jvc") || a.includes("jvt") || a.includes("jumeirah village")) return "Dubai Marina";
  if (a.includes("silicon oasis") || a.includes("academic city") || a.includes("nad al sheba") || a.includes("international city")) return "Silicon Oasis";
  if (a.includes("sharjah") || a.includes("muwailih")) return "Sharjah";
  if (a.includes("ajman")) return "Ajman";
  return "Other Dubai";
}

